// Iterate log from last Checkpoint LSN
while (log.has_next()) {
LogRecord record = log.next();
if (record.type() == RecordType::UPDATE) {
uint32_t pid = record.page_id();
// The FIRST time a page is seen in the log
// its LSN is recorded as the rec_lsn.
if (dpt.find(pid) == dpt.end()) {
dpt[pid] = record.lsn();
}
}
}

// Determine starting point for Redo Phase
uint64_t redo_start_lsn = UINT64_MAX;
for (const auto& [id, lsn] : dpt) {
redo_start_lsn = std::min(redo_start_lsn, lsn);
}
